import json
b = json.load(open('baseline-packages.json'))
a = json.load(open('after-cpm-packages.json'))
bp = {p['id']: p['resolvedVersion'] for p in b['projects'][0]['frameworks'][0]['topLevelPackages']}
ap = {p['id']: p['resolvedVersion'] for p in a['projects'][0]['frameworks'][0]['topLevelPackages']}
changes = {k: (bp[k], ap[k]) for k in bp if bp.get(k) != ap.get(k)}
if not changes:
    print('All packages resolve to identical versions. Conversion is version-neutral.')
else:
    for k,(bv,av) in changes.items():
        print(f'{k}: {bv} -> {av}')
"

